with open('web/static/css/player.css', 'a', encoding='utf-8') as f:
    f.write('\n/* Fix player control symmetry */\n')
    f.write('.pb-ctrl {\n')
    f.write('    position: relative;\n')
    f.write('}\n')
    f.write('.pb-badges {\n')
    f.write('    position: absolute !important;\n')
    f.write('    right: 0;\n')
    f.write('    top: 50%;\n')
    f.write('    transform: translateY(-50%);\n')
    f.write('}\n')
print('Appended pb-badges absolute positioning to player.css!')
